export const R1_WORKSTEAL_HINT_CONTRACT_ID =
  'gnosis.protocol69.r1-worksteal.deterministic-fib-hint.v1';
export const R1_WORKSTEAL_HINT_THEOREM_ID =
  'FoilLoserPolicy.r1_idle_witness_may_try_deterministic_work_hint';

