export const R1_WORKSTEAL_QUEUE_SUMMARY_CONTRACT_ID =
  'gnosis.protocol69.r1-worksteal.queue-flow-summary.v1';

export const R1_WORKSTEAL_RECEIPT_SUBMISSION_SCHEMA_VERSION =
  'gnosis.protocol69.r1-worksteal-receipt-submission.v1';
export const R1_WORKSTEAL_RECEIPT_SUBMISSION_CONTRACT_ID =
  'gnosis.protocol69.r1-worksteal.receipt-submission.v1';
export const R1_WORKSTEAL_RECEIPT_SUBMISSION_THEOREM_ID =
  'FoilLoserPolicy.r1_receipt_submission_preserves_reuse_right_boundary';

